        self.initialize_board()

    def initialize_board(self):
        for i in range(3):
            for j in range((i % 2) + 1, 8, 2):
                self._board[i][j] = Piece('white', 'normal')
        for i in range(5, 8):
            for j in range((i % 2) + 1, 8, 2):
                self._board[i][j] = Piece('black', 'normal')

    def display(self):
        print("  a b c d e f g h")
        for i, row in enumerate(self._board):
            print(f"{8 - i} {self.to_string(row)}")

    def to_string(self, row):
        return " ".join(piece.symbol if piece else '.' for piece in row)

    def update(self, move):
        start, end = move
        self._board[end[0]][end[1]] = self._board[start[0]][start[1]]
